SELECT

FROM t_button_config a


    a.is_deleted = 0
    ${dataScope}

        AND a.button_key LIKE concat('%',#{buttonKey},'%')


        AND a.button_name LIKE concat('%',#{buttonName},'%')


        AND a.button_status = #{buttonStatus}




        ORDER BY ${page.orderBy}


        ORDER BY a.id ASC

